import { useAuth } from "@/contexts/AuthContext";
import { useUserRole } from "@/hooks/useUserRole";
import { useMerchantRestaurants } from "@/hooks/useActivityParticipation";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Edit, MapPin, Phone, Star, Loader2, Globe, Plus, ShieldCheck, ShieldOff, ArrowUpCircle, ArrowDownCircle } from "lucide-react";
import { Link, useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { RestaurantFormDialog } from "@/components/admin/RestaurantFormDialog";
import { useEffect, useState } from "react";
import { useProfile } from "@/hooks/useProfile";
import { useToast } from "@/hooks/use-toast";
import { useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import CreateStoreDialog from "@/components/merchant/CreateStoreDialog";

const storeLimits: Record<string, number> = { vip1: 1, vip2: 3, vip3: 999 };

const MerchantDashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const { t } = useTranslation();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { isMerchant, isSupervisor, isLoading: roleLoading, canAccessMerchantDashboard } = useUserRole();
  const { data: restaurants = [], isLoading } = useMerchantRestaurants();
  const { localizeRestaurant } = useLocalizedContent();
  const { data: profile } = useProfile();
  const [updatingId, setUpdatingId] = useState<string | null>(null);

  const vipLevel = profile?.vip_level as string | null;
  const vipExpiresAt = profile?.vip_expires_at as string | null;
  const isVipActive = vipLevel && vipExpiresAt && new Date(vipExpiresAt) > new Date();
  const maxComplete = isVipActive ? (storeLimits[vipLevel] || 1) : 0;
  const currentCompleteCount = restaurants.filter((r: any) => r.store_level === "complete").length;

  useEffect(() => {
    if (!roleLoading && !canAccessMerchantDashboard) {
      navigate("/");
    }
  }, [roleLoading, canAccessMerchantDashboard, navigate]);

  const handleStoreLevel = async (restaurantId: string, action: "upgrade" | "downgrade") => {
    setUpdatingId(restaurantId);
    try {
      const { data, error } = await supabase.functions.invoke("update-store-level", {
        body: { restaurant_id: restaurantId, action },
      });
      if (error) throw error;
      if (data?.error) throw new Error(data.error);

      toast({
        title: action === "upgrade"
          ? t("merchant.storeUpgraded", "餐厅已升级")
          : t("merchant.storeDowngraded", "餐厅已降级"),
        description: action === "upgrade"
          ? t("merchant.storeUpgradedDesc", "该餐厅已升级为完整版")
          : t("merchant.storeDowngradedDesc", "该餐厅已降级为基础版"),
      });
      queryClient.invalidateQueries({ queryKey: ["merchantRestaurants"] });
    } catch (e: any) {
      toast({
        title: t("common.error", "错误"),
        description: e.message || t("merchant.storeLevelFailed", "操作失败"),
        variant: "destructive",
      });
    } finally {
      setUpdatingId(null);
    }
  };

  if (isLoading || roleLoading) {
    return (
      <div className="flex justify-center items-center min-h-[50vh]">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div>
      <div className="mb-8">
        <h1 className="text-3xl font-bold mb-2">{t("merchant.myRestaurants")}</h1>
        <p className="text-muted-foreground">
          {isSupervisor ? t("merchant.supervisorDescription") : t("merchant.merchantDescription")}
        </p>
        {isVipActive && (
          <div className="mt-2 flex items-center gap-2 text-sm text-muted-foreground">
            <ShieldCheck className="w-4 h-4 text-primary" />
            <span>
              {t("merchant.completeSlots", "完整版名额")}: {currentCompleteCount} / {maxComplete === 999 ? "∞" : maxComplete}
            </span>
          </div>
        )}
      </div>

      {restaurants.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-muted-foreground mb-4">{t("merchant.noRestaurants")}</p>
            <CreateStoreDialog
              trigger={
                <Button>
                  <Plus className="w-4 h-4 mr-1" />
                  {t("merchant.createStore", "创建商店")}
                </Button>
              }
            />
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {restaurants.map((restaurant) => {
            const localized = localizeRestaurant(restaurant);
            const storeLevel = (restaurant as any).store_level || "shell";
            const isComplete = storeLevel === "complete";
            const canUpgrade = isVipActive && !isComplete && currentCompleteCount < maxComplete;
            const canDowngrade = isComplete;
            const isUpdating = updatingId === restaurant.id;

            return (
              <Card key={restaurant.id} className="overflow-hidden hover:shadow-lg transition-shadow">
                <div className="relative h-48 overflow-hidden">
                  <img
                    src={restaurant.image_url || "/placeholder.svg"}
                    alt={localized.name}
                    className="w-full h-full object-cover"
                  />
                  {/* Store level badge */}
                  <div className="absolute top-2 right-2">
                    <Badge
                      variant={isComplete ? "default" : "secondary"}
                      className={isComplete ? "bg-green-600 hover:bg-green-700 text-white" : ""}
                    >
                      {isComplete ? (
                        <><ShieldCheck className="w-3 h-3 mr-1" />{t("merchant.complete", "完整版")}</>
                      ) : (
                        <><ShieldOff className="w-3 h-3 mr-1" />{t("merchant.shell", "基础版")}</>
                      )}
                    </Badge>
                  </div>
                </div>
                <CardHeader>
                  <CardTitle className="flex items-start justify-between gap-2">
                    <span className="line-clamp-1">{localized.name}</span>
                    {restaurant.rating && (
                      <div className="flex items-center gap-1 text-sm">
                        <Star className="w-4 h-4 fill-primary text-primary" />
                        <span>{restaurant.rating}</span>
                      </div>
                    )}
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-3">
                  {restaurant.type && restaurant.type.length > 0 && (
                    <div className="flex flex-wrap gap-1">
                      {localized.type.slice(0, 3).map((type: string, idx: number) => (
                        <span
                          key={idx}
                          className="text-xs px-2 py-1 bg-secondary text-secondary-foreground rounded"
                        >
                          {type}
                        </span>
                      ))}
                    </div>
                  )}

                  {restaurant.address && (
                    <div className="flex items-start gap-2 text-sm text-muted-foreground">
                      <MapPin className="w-4 h-4 mt-0.5 flex-shrink-0" />
                      <span className="line-clamp-2">{restaurant.address}</span>
                    </div>
                  )}

                  {restaurant.phone && (
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <Phone className="w-4 h-4 flex-shrink-0" />
                      <span>{restaurant.phone}</span>
                    </div>
                  )}

                  {(restaurant as any).official_website && (
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <Globe className="w-4 h-4 flex-shrink-0" />
                      <a
                        href={(restaurant as any).official_website}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-primary hover:underline line-clamp-1"
                      >
                        {t("restaurant.visitWebsite")}
                      </a>
                    </div>
                  )}

                  {/* Upgrade/Downgrade button */}
                  {isVipActive && (
                    <div className="pt-1">
                      {canUpgrade && (
                        <Button
                          variant="outline"
                          size="sm"
                          className="w-full text-green-600 border-green-300 hover:bg-green-50 dark:hover:bg-green-950/20"
                          onClick={() => handleStoreLevel(restaurant.id, "upgrade")}
                          disabled={isUpdating}
                        >
                          {isUpdating ? (
                            <Loader2 className="h-3.5 w-3.5 animate-spin mr-1" />
                          ) : (
                            <ArrowUpCircle className="h-3.5 w-3.5 mr-1" />
                          )}
                          {t("merchant.upgradeToComplete", "升级为完整版")}
                        </Button>
                      )}
                      {canDowngrade && (
                        <Button
                          variant="ghost"
                          size="sm"
                          className="w-full text-muted-foreground hover:text-destructive"
                          onClick={() => handleStoreLevel(restaurant.id, "downgrade")}
                          disabled={isUpdating}
                        >
                          {isUpdating ? (
                            <Loader2 className="h-3.5 w-3.5 animate-spin mr-1" />
                          ) : (
                            <ArrowDownCircle className="h-3.5 w-3.5 mr-1" />
                          )}
                          {t("merchant.downgradeToShell", "降级为基础版")}
                        </Button>
                      )}
                    </div>
                  )}

                  <div className="flex gap-2 pt-2">
                    <Button
                      asChild
                      variant="outline"
                      size="sm"
                      className="flex-1"
                    >
                      <Link to={`/restaurant/${restaurant.id}`}>
                        {t("restaurants.viewDetails")}
                      </Link>
                    </Button>
                    <RestaurantFormDialog
                      restaurant={restaurant}
                      trigger={
                        <Button variant="default" size="sm" className="flex-1">
                          <Edit className="w-4 h-4 mr-1" />
                          {t("common.edit")}
                        </Button>
                      }
                    />
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default MerchantDashboard;
